async def test_active_user(
    self,
    test_app_client: tuple[httpx.AsyncClient, bool],
    user: UserModel,
):
    client, requires_verification = test_app_client
    response = await client.get(
        "/me", headers={"Authorization": f"Bearer {user.id}"}
