class AccessTokenDatabaseMock(AccessTokenDatabase[AccessTokenModel]):
    store: dict[str, AccessTokenModel]

    def __init__(self):
        self.store = {}

    async def get_by_token(
        self, token: str, max_age: Optional[datetime] = None
    ) -> Optional[AccessTokenModel]:
        try:
